'use client';

import { Suspense, useState, useEffect } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { pricingPlans, validPromoCodes } from '@/lib/mockData';
import { motion } from 'framer-motion';
import { cn } from '@/lib/utils';
import { Check, ChevronRight, Loader2, Tag, X } from 'lucide-react';
import Link from 'next/link';

function RegisterForm() {
  const searchParams = useSearchParams();
  const initialPlanId = searchParams.get('plan') || 'basic';
  
  const [selectedPlanId, setSelectedPlanId] = useState(initialPlanId);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState(1); // 1: Details, 2: Review & Payment, 3: Success
  const [paymentMethod, setPaymentMethod] = useState<'online' | 'offline'>('online');
  
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
  });

  // Promo Code State
  const [promoCode, setPromoCode] = useState('');
  const [appliedDiscount, setAppliedDiscount] = useState<{ code: string, value: number, type: 'percent' | 'fixed' } | null>(null);
  const [promoStatus, setPromoStatus] = useState<'idle' | 'validating' | 'success' | 'error'>('idle');
  const [promoMessage, setPromoMessage] = useState('');

  // Update selected plan if URL changes
  useEffect(() => {
    const plan = searchParams.get('plan');
    if (plan) setSelectedPlanId(plan);
  }, [searchParams]);

  const selectedPlan = pricingPlans.find(p => p.id === selectedPlanId) || pricingPlans[0];
  const basePrice = parseInt(selectedPlan.price.replace('₹', ''));
  
  const finalPrice = appliedDiscount 
    ? appliedDiscount.type === 'percent' 
      ? basePrice - (basePrice * appliedDiscount.value / 100)
      : Math.max(0, basePrice - appliedDiscount.value)
    : basePrice;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const validatePromoCode = async () => {
    const code = promoCode.trim().toUpperCase();
    if (!code) {
      setPromoStatus('error');
      setPromoMessage('Please enter a code');
      return;
    }

    const securePattern = /^[A-Z0-9]{3,15}$/;
    if (!securePattern.test(code)) {
       setPromoStatus('error');
       setPromoMessage('Invalid code format');
       return;
    }

    setPromoStatus('validating');
    await new Promise(resolve => setTimeout(resolve, 1000));
    const validCode = validPromoCodes.find(c => c.code === code);

    if (validCode) {
      setAppliedDiscount({ code: validCode.code, value: validCode.value, type: validCode.discountType });
      setPromoStatus('success');
      setPromoMessage(`${validCode.discountType === 'percent' ? validCode.value + '%' : '₹' + validCode.value} discount applied!`);
    } else {
      setAppliedDiscount(null);
      setPromoStatus('error');
      setPromoMessage('Invalid or expired code');
    }
  };

  const handleApplyPromo = (e: React.MouseEvent) => {
    e.preventDefault();
    validatePromoCode();
  };
  
  const handleRemovePromo = () => {
    setAppliedDiscount(null);
    setPromoCode('');
    setPromoStatus('idle');
    setPromoMessage('');
  };

  const handleNextStep = (e: React.FormEvent) => {
    e.preventDefault();
    setStep(2);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleFinalSubmit = async () => {
    setLoading(true);
    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 2000));
    setLoading(false);
    setStep(3);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // --- Step 3: Success & Onboarding ---
  if (step === 3) {
    return (
      <motion.div 
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="max-w-xl mx-auto text-center"
      >
        <div className="w-24 h-24 bg-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 shadow-[0_0_30px_rgba(16,185,129,0.4)]">
          <Check className="text-slate-950 w-12 h-12" strokeWidth={4} />
        </div>
        <h2 className="text-4xl font-black text-white mb-2 tracking-tight">Welcome to the Club, {formData.firstName}!</h2>
        <p className="text-xl text-slate-400 mb-8">
          Your <span className="text-neon font-bold">{selectedPlan.name}</span> spot is reserved.
        </p>
        
        <div className="bg-amber-500/10 border border-amber-500/20 rounded-xl p-4 mb-8 text-left flex items-start gap-3">
             <div className="p-2 bg-amber-500/10 rounded-lg text-amber-500 mt-0.5">
                 <Loader2 className="animate-spin-slow" size={20} />
             </div>
             <div>
                 <h4 className="font-bold text-amber-500 text-sm uppercase tracking-wider mb-1">Action Required</h4>
                 <p className="text-sm text-slate-300">
                     We've sent a verification link to <span className="text-white font-medium">{formData.email}</span>. 
                     Please click it to activate your full account access.
                 </p>
             </div>
        </div>

        <Link 
          href="/dashboard"
          className="inline-flex items-center gap-2 bg-neon text-slate-950 px-8 py-4 rounded-xl font-bold hover:bg-neon-hover transition-all shadow-lg hover:shadow-neon/20 transform hover:-translate-y-1"
        >
          Go to Member Dashboard <ChevronRight size={20} />
        </Link>
      </motion.div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12 items-start">
      
      {/* Left Column - Main Content */}
      <div className="lg:col-span-7 space-y-8">
        <div>
          <h1 className="text-4xl md:text-5xl font-black text-white px-1 tracking-tighter mb-4">
            {step === 1 ? 'Join PulseFit' : 'Review & Pay'}
          </h1>
          <p className="text-slate-400 text-lg">
            {step === 1 
                ? "You're one step away from transforming your life. Fill in the details below." 
                : "Review your details and select a payment method to secure your spot."}
          </p>
        </div>

        {/* --- Step 2: Review (Summary) --- */}
        {step === 2 && (
            <motion.div 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="bg-slate-900 border border-slate-800 rounded-2xl p-6"
            >
                <div className="flex justify-between items-center mb-4 border-b border-slate-800 pb-4">
                    <h3 className="font-bold text-white text-lg">Personal Details</h3>
                    <button 
                        onClick={() => setStep(1)}
                        className="text-sm text-neon hover:underline font-medium"
                    >
                        Edit
                    </button>
                </div>
                <div className="grid grid-cols-2 gap-y-4 text-sm">
                    <div>
                        <div className="text-slate-500">Name</div>
                        <div className="text-white font-medium">{formData.firstName} {formData.lastName}</div>
                    </div>
                    <div>
                        <div className="text-slate-500">Phone</div>
                        <div className="text-white font-medium">{formData.phone}</div>
                    </div>
                    <div className="col-span-2">
                        <div className="text-slate-500">Email</div>
                        <div className="text-white font-medium">{formData.email}</div>
                    </div>
                </div>
            </motion.div>
        )}

        {/* --- Step 1: Form Fields --- */}
        <form onSubmit={handleNextStep} className={cn("space-y-6", step !== 1 && "hidden")}>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-sm font-bold text-slate-300 ml-1">First Name</label>
              <input 
                type="text" 
                name="firstName"
                required
                className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-neon/50 focus:ring-1 focus:ring-neon/50 transition-all"
                placeholder="Jane"
                value={formData.firstName}
                onChange={handleInputChange}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-slate-300 ml-1">Last Name</label>
              <input 
                type="text" 
                name="lastName"
                required
                className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-neon/50 focus:ring-1 focus:ring-neon/50 transition-all"
                placeholder="Doe"
                value={formData.lastName}
                onChange={handleInputChange}
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-300 ml-1">Email Address</label>
            <input 
              type="email" 
              name="email"
              required
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-neon/50 focus:ring-1 focus:ring-neon/50 transition-all"
              placeholder="jane@example.com"
              value={formData.email}
              onChange={handleInputChange}
            />
          </div>

          <div className="space-y-2">
             <label className="text-sm font-bold text-slate-300 ml-1">Phone Number</label>
             <input 
                type="tel" 
                name="phone"
                required
                className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-neon/50 focus:ring-1 focus:ring-neon/50 transition-all"
                placeholder="+1 (555) 000-0000"
                value={formData.phone}
                onChange={handleInputChange}
             />
          </div>

          <div className="pt-4">
            <button 
              type="submit" 
              className="w-full bg-neon text-slate-950 font-black text-lg py-4 rounded-xl hover:bg-neon-hover shadow-lg shadow-neon/20 transition-all flex items-center justify-center gap-2"
            >
              Next Step <ChevronRight size={20} />
            </button>
            <p className="text-center text-slate-500 text-xs mt-4">
              By continuing, you agree to our Terms of Service and Privacy Policy.
            </p>
          </div>
        </form>

        {/* --- Step 2: Payment Selector & Actions --- */}
        {step === 2 && (
            <div className="space-y-6">
                <div className="space-y-4">
                    <h3 className="text-white font-bold text-lg">Select Payment Method</h3>
                    
                    {/* Option A: Online */}
                    <div 
                        onClick={() => setPaymentMethod('online')}
                        className={cn(
                            "cursor-pointer border rounded-xl p-5 flex items-center gap-4 transition-all relative overflow-hidden",
                            paymentMethod === 'online' ? "bg-slate-800 border-neon ring-1 ring-neon/50" : "bg-slate-900/50 border-white/10 hover:border-white/20"
                        )}
                    >
                        <div className={cn("w-5 h-5 rounded-full border-2 flex items-center justify-center flex-shrink-0", paymentMethod === 'online' ? "border-neon bg-neon" : "border-slate-500")}>
                            {paymentMethod === 'online' && <div className="w-2 h-2 rounded-full bg-slate-950" />}
                        </div>
                        <div className="flex-1">
                            <div className="font-bold text-white mb-1">Pay Online</div>
                            <div className="text-sm text-slate-400">Credit Card, Debit Card, UPI</div>
                        </div>
                        <div className="flex gap-2 opacity-50">
                             {/* Payment Logos Placeholder */}
                             <div className="w-8 h-5 bg-white/20 rounded"></div>
                             <div className="w-8 h-5 bg-white/20 rounded"></div>
                        </div>
                    </div>

                    {/* Option B: Pay at Gym */}
                    <div 
                        onClick={() => setPaymentMethod('offline')}
                        className={cn(
                            "cursor-pointer border rounded-xl p-5 flex items-center gap-4 transition-all relative overflow-hidden",
                            paymentMethod === 'offline' ? "bg-slate-800 border-neon ring-1 ring-neon/50" : "bg-slate-900/50 border-white/10 hover:border-white/20"
                        )}
                    >
                        <div className={cn("w-5 h-5 rounded-full border-2 flex items-center justify-center flex-shrink-0", paymentMethod === 'offline' ? "border-neon bg-neon" : "border-slate-500")}>
                            {paymentMethod === 'offline' && <div className="w-2 h-2 rounded-full bg-slate-950" />}
                        </div>
                        <div className="flex-1">
                            <div className="font-bold text-white mb-1 flex items-center gap-2">
                                Pay at Gym
                                <span className="text-[10px] uppercase font-bold text-slate-950 bg-neon px-1.5 py-0.5 rounded">Recommended</span>
                            </div>
                            <div className="text-sm text-slate-400">Complete your registration now and pay when you arrive for your first workout.</div>
                        </div>
                    </div>
                    {paymentMethod === 'offline' && (
                        <div className="bg-blue-500/10 text-blue-400 text-xs p-3 rounded-lg flex items-start gap-2">
                             <Tag size={14} className="mt-0.5 flex-shrink-0" />
                             Your spot will be reserved for 48 hours. Please visit the reception to finalize your payment.
                        </div>
                    )}
                </div>

                <button 
                  onClick={handleFinalSubmit}
                  disabled={loading}
                  className="w-full bg-neon text-slate-950 font-black text-lg py-4 rounded-xl hover:bg-neon-hover shadow-lg shadow-neon/20 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                  {loading ? (
                    <>
                      <Loader2 className="animate-spin" /> Processing...
                    </>
                  ) : (
                    <>
                      {paymentMethod === 'online' ? `Pay ₹${finalPrice.toFixed(2)} Now` : 'Confirm Booking'}
                    </>
                  )}
                </button>
            </div>
        )}

      </div>

      {/* Right Column - Plan Selection & Summary */}
      <motion.div 
        initial={{ opacity: 0, x: 20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ delay: 0.2 }}
        className="lg:col-span-5 bg-slate-900/50 border border-white/5 rounded-3xl p-6 md:p-8 sticky top-32"
      >
        <h3 className="text-xl font-bold text-white mb-6">
            {step === 1 ? 'Select Membership Plan' : 'Order Summary'}
        </h3>
        
        {/* Step 1: Interactive Plan Selector */}
        {step === 1 ? (
            <div className="space-y-4 mb-8">
            {pricingPlans.map((plan) => (
                <div 
                key={plan.id}
                onClick={() => setSelectedPlanId(plan.id)}
                className={cn(
                    "cursor-pointer border rounded-2xl p-4 transition-all duration-200 flex items-center justify-between group",
                    selectedPlanId === plan.id 
                    ? "bg-slate-800 border-neon/50 ring-1 ring-neon/50" 
                    : "bg-slate-950/50 border-white/5 hover:border-white/20"
                )}
                >
                <div className="flex items-center gap-4">
                    <div className="flex-1">
                        <h4 className={cn("font-bold", selectedPlanId === plan.id ? "text-white" : "text-slate-300")}>
                        {plan.name}
                        </h4>
                    </div>
                </div>
                <div className="text-lg font-black text-white">
                    {plan.price}<span className="text-xs font-medium text-slate-500">/mo</span>
                </div>
                </div>
            ))}
            </div>
        ) : (
            // Step 2: Static Plan Display
            <div className="mb-8 p-4 rounded-2xl bg-slate-800 border border-white/10 flex justify-between items-center group">
                 <div>
                    <h4 className="font-bold text-white">{selectedPlan.name}</h4>
                    <span className="text-xs text-slate-400">Billed Monthly</span>
                 </div>
                 <div className="text-right">
                    <div className="text-white font-bold">{selectedPlan.price}</div>
                    <button 
                        onClick={() => setStep(1)} 
                        className="text-xs text-neon hover:underline"
                    >
                        Change
                    </button>
                 </div>
            </div>
        )}

        {/* Promo Code Section */}
        <div className="mb-8">
           <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">Promo Code</label>
           <div className="flex gap-2">
             <div className="relative flex-1">
                 <Tag className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4" />
                 <input 
                   type="text" 
                   value={promoCode}
                   onChange={(e) => {
                     setPromoCode(e.target.value);
                     if (promoStatus === 'error') {
                        setPromoStatus('idle');
                        setPromoMessage('');
                     }
                   }}
                   disabled={promoStatus === 'success' || promoStatus === 'validating'}
                   placeholder="Enter code"
                   className={cn(
                     "w-full bg-slate-950/80 border rounded-xl pl-9 pr-4 py-3 text-sm focus:outline-none transition-all uppercase",
                     promoStatus === 'error' ? "border-red-500 text-red-100" :
                     promoStatus === 'success' ? "border-green-500 text-green-100" :
                     "border-white/10 text-white focus:border-neon/50"
                   )}
                 />
                 {promoStatus === 'success' && (
                    <button 
                      onClick={handleRemovePromo}
                      className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"
                    >
                       <X size={14} />
                    </button>
                 )}
             </div>
             <button
               onClick={handleApplyPromo}
               disabled={!promoCode || promoStatus === 'validating' || promoStatus === 'success'}
               className="bg-white/10 text-white px-5 py-3 rounded-xl text-sm font-bold hover:bg-white/20 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
                {promoStatus === 'validating' ? <Loader2 className="animate-spin w-4 h-4" /> : 'Apply'}
             </button>
           </div>
           
           {/* Validation Message */}
           {promoMessage && (
             <motion.p 
               initial={{ opacity: 0, y: -5 }}
               animate={{ opacity: 1, y: 0 }}
               className={cn(
                 "text-xs mt-2 font-medium flex items-center gap-1.5",
                 promoStatus === 'success' ? "text-green-400" : "text-red-400"
               )}
             >
               {promoStatus === 'success' && <Check size={12} strokeWidth={4} />}
               {promoMessage}
             </motion.p>
           )}
        </div>

        <div className="pt-8 border-t border-white/5">
           <div className="flex justify-between items-center mb-4">
              <span className="text-slate-400">Subtotal</span>
              <span className="text-white font-medium">₹{basePrice}</span>
           </div>
           
           {appliedDiscount && (
             <motion.div 
               initial={{ opacity: 0, height: 0 }}
               animate={{ opacity: 1, height: 'auto' }}
               className="flex justify-between items-center mb-4 text-neon"
             >
                <span className="flex items-center gap-2">
                   <Tag size={14} /> 
                   <span>Discount ({appliedDiscount.code})</span>
                </span>
                <span className="font-bold">
                   -{appliedDiscount.type === 'percent' 
                       ? `${appliedDiscount.value}%` 
                       : `₹${appliedDiscount.value}`}
                </span>
             </motion.div>
           )}

           <div className="flex justify-between items-center mb-4">
              <span className="text-slate-400">Initiation Fee</span>
              <span className="text-neon font-medium">WAIVED</span>
           </div>
           <div className="flex justify-between items-center text-xl font-black text-white pt-4 border-t border-white/5">
              <span>Total today</span>
              <div className="text-right">
                {appliedDiscount && (
                   <span className="text-sm text-slate-500 line-through mr-2 block font-medium">₹{basePrice}</span>
                )}
                <span>₹{finalPrice.toFixed(2)}</span>
              </div>
           </div>
        </div>
      </motion.div>
    </div>
  );
}

export default function RegisterPage() {
  return (
    <div className="min-h-screen pt-32 pb-20 px-4 relative overflow-hidden">
       {/* Background Elements */}
       <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-neon/10 blur-[120px] -z-10 rounded-full mix-blend-screen" />
       
       <Suspense fallback={
         <div className="flex items-center justify-center min-h-[50vh]">
           <Loader2 className="animate-spin text-neon w-10 h-10" />
         </div>
       }>
          <RegisterForm />
       </Suspense>
    </div>
  );
}

'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { cn } from '@/lib/utils';
import { 
  BarChart, 
  Users, 
  Calendar, 
  Settings, 
  LogOut, 
  Activity, 
  ShieldCheck,
  ChevronLeft,
  ChevronRight,
  TrendingUp,
  UserCog,
  Plus,
  CreditCard
} from 'lucide-react';

interface SidebarProps {
  isOpen: boolean;
  toggleSidebar: () => void;
}

const menuItems = [
  { icon: BarChart, label: 'Dashboard', href: '/admin' },
  { icon: Users, label: 'Members', href: '/admin/members' },
  { icon: Calendar, label: 'Schedule', href: '/admin/schedule' },
  { icon: TrendingUp, label: 'Sales Leads', href: '/admin/leads' },
  { icon: ShieldCheck, label: 'Access Log', href: '/admin/access' },
  { icon: UserCog, label: 'Staff', href: '/admin/staff' },
  { icon: CreditCard, label: 'Manage Plans', href: '/admin/plans' },
  { icon: Activity, label: 'Maintenance', href: '/admin/maintenance' },
];

export default function Sidebar({ isOpen, toggleSidebar }: SidebarProps) {
  const pathname = usePathname();

  return (
    <aside 
      className={cn(
        "fixed top-0 left-0 z-40 h-screen transition-all duration-300 ease-in-out bg-[#0a0f1c] border-r border-slate-800",
        isOpen ? "w-64" : "w-20"
      )}
    >
      <div className="flex flex-col h-full bg-[#0a0f1c]">
        {/* Header */}
        <div className="h-16 flex items-center justify-between px-4 border-b border-slate-800/50">
          <Link href="/admin" className={cn("flex items-center gap-2 overflow-hidden whitespace-nowrap", !isOpen && "justify-center w-full")}>
             <div className="w-8 h-8 flex-shrink-0 bg-neon rounded-lg flex items-center justify-center text-slate-950">
                <Activity size={20} className="stroke-[3]" />
             </div>
             {isOpen && (
               <span className="font-bold text-xl text-white tracking-tight">Pulse<span className="text-neon">Admin</span></span>
             )}
          </Link>
        </div>

        {/* Quick Action */}
        <div className="p-3">
            <button className={cn(
                "w-full flex items-center gap-2 bg-slate-800 hover:bg-slate-700 text-white rounded-lg transition-all border border-slate-700 hover:border-slate-600 group",
                isOpen ? "px-4 py-2.5" : "p-2 justify-center aspect-square"
            )}>
                <div className="bg-neon text-slate-950 rounded flex items-center justify-center w-5 h-5 flex-shrink-0">
                    <Plus size={14} strokeWidth={3} />
                </div>
                {isOpen && <span className="text-sm font-bold whitespace-nowrap">Add Member</span>}
            </button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 py-2 px-3 space-y-1 overflow-y-auto custom-scrollbar">
           {menuItems.map((item) => {
             const isActive = pathname === item.href || (pathname.startsWith(item.href) && item.href !== '/admin');
             return (
               <Link 
                  key={item.href} 
                  href={item.href}
                  className={cn(
                    "flex items-center gap-3 px-3 py-3 rounded-xl transition-all duration-200 group relative",
                    isActive ? "bg-gradient-to-r from-neon/20 to-transparent text-white" : "text-slate-400 hover:bg-slate-800/50 hover:text-white",
                    !isOpen && "justify-center"
                  )}
               >
                 {isActive && (
                    <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-neon rounded-r-full" />
                 )}
                 <item.icon size={20} className={cn("flex-shrink-0 transition-transform", isActive ? "text-neon scale-110" : "group-hover:text-slate-300")} />
                 {isOpen && (
                   <span className="font-medium whitespace-nowrap">{item.label}</span>
                 )}
                 {!isOpen && (
                    <div className="absolute left-full ml-4 px-2 py-1 bg-slate-800 text-white text-xs rounded opacity-0 group-hover:opacity-100 pointer-events-none whitespace-nowrap z-50 transition-opacity">
                       {item.label}
                    </div>
                 )}
               </Link>
             )
           })}
        </nav>

        {/* User / Footer */}
        <div className="p-4 border-t border-slate-800/50 bg-[#0a0f1c]">
            <button className={cn("flex items-center gap-3 w-full text-left p-2 rounded-xl hover:bg-slate-800/50 transition-colors group", !isOpen && "justify-center")}>
                <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-emerald-500 to-cyan-500 p-[1px]">
                   <div className="w-full h-full rounded-full bg-slate-900 flex items-center justify-center overflow-hidden">
                       <img src="/demo-images/avatar-admin.jpg" alt="Admin" className="w-full h-full object-cover opacity-90" />
                   </div>
                </div>
                {isOpen && (
                    <div className="flex-1 overflow-hidden">
                        <div className="text-sm font-bold text-white truncate">Marcus Admin</div>
                        <div className="text-xs text-slate-500 truncate">Station Manager</div>
                    </div>
                )}
                {isOpen && <LogOut size={16} className="text-slate-500 group-hover:text-red-400 transition-colors" />}
            </button>
        </div>

        {/* Toggle Button (Floating) */}
        <button 
           onClick={toggleSidebar}
           className="absolute -right-3 top-20 bg-slate-800 border border-slate-700 text-slate-400 hover:text-white w-6 h-6 rounded-full flex items-center justify-center shadow-lg transition-transform hover:scale-110 z-50"
        >
           {isOpen ? <ChevronLeft size={14} /> : <ChevronRight size={14} />}
        </button>
      </div>
    </aside>
  );
}

'use client';

import React from 'react';
import { useGymStore } from '@/lib/store';
import { cn } from '@/lib/utils';
import { Activity } from 'lucide-react';

export default function CrowdMeter() {
  const { occupancy } = useGymStore();

  let status = 'Quiet';
  let color = 'bg-emerald-500';
  let textColor = 'text-emerald-500';
  let pulse = false;

  if (occupancy > 40 && occupancy <= 75) {
    status = 'Moderate';
    color = 'bg-amber-500';
    textColor = 'text-amber-500';
  } else if (occupancy > 75) {
    status = 'Busy';
    color = 'bg-red-500';
    textColor = 'text-red-500';
    pulse = true;
  }

  return (
    <div className="flex items-center gap-2 bg-slate-900/50 px-3 py-1.5 rounded-full border border-slate-800">
      <div className="relative flex items-center justify-center w-3 h-3">
        {pulse && (
           <span className={cn("absolute inline-flex h-full w-full rounded-full opacity-75 animate-ping", color)}></span>
        )}
        <span className={cn("relative inline-flex rounded-full h-2 w-2", color)}></span>
      </div>
      <div className="flex flex-col leading-none">
          <span className="text-[10px] text-slate-400 font-medium uppercase tracking-wider">Live Crowd</span>
          <span className={cn("text-xs font-bold", textColor)}>{status}</span>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { cn } from '@/lib/utils';
import { Activity, Menu, X } from 'lucide-react';
import CrowdMeter from '@/components/layout/CrowdMeter';
import { motion, AnimatePresence } from 'framer-motion';

export default function Navbar() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const navLinks = [
    { href: '/facility', label: 'Facility' },
    { href: '/about', label: 'About' },
    { href: '/#contact', label: 'Contact Us' },
  ];

  return (
    <>
      <nav className="fixed top-4 md:top-8 left-1/2 -translate-x-1/2 z-50 w-full max-w-[95%] md:max-w-4xl px-2 md:px-4">
        <div className="flex items-center justify-between bg-slate-900/80 backdrop-blur-xl border border-white/10 px-4 md:px-6 py-3 rounded-full shadow-2xl ring-1 ring-white/5">
          {/* Logo */}
          <Link href="/#hero" className="flex items-center gap-2 group z-50 relative" onClick={() => setIsMenuOpen(false)}>
            <div className="w-8 h-8 rounded-full bg-neon flex items-center justify-center text-slate-950">
               <Activity size={18} strokeWidth={3} />
            </div>
            <span className="text-lg font-bold italic tracking-tighter text-white">
              Pulse<span className="text-neon transition-colors group-hover:text-white">Fit</span>
            </span>
          </Link>
          
          {/* Desktop Links */}
          <div className="hidden md:flex items-center gap-8 text-sm font-medium text-slate-400">
            {navLinks.map(link => (
              <Link key={link.href} href={link.href} className="hover:text-neon transition-colors">
                {link.label}
              </Link>
            ))}
          </div>

          {/* Desktop Actions */}
          <div className="hidden md:flex items-center gap-4">
             <CrowdMeter />
             <div className="h-4 w-px bg-white/10" />
             <Link href="/login" className="text-sm font-medium text-slate-400 hover:text-white transition-colors">
               Login
             </Link>
             <Link href="/pricing" className="bg-neon text-slate-950 font-bold px-6 py-2.5 rounded-full text-sm hover:bg-neon-hover transition-colors shadow-[0_0_20px_rgba(190,242,100,0.3)] hover:shadow-[0_0_30px_rgba(190,242,100,0.5)]">
               Join Now
             </Link>
          </div>

          {/* Mobile Actions & Toggle */}
          <div className="flex items-center gap-3 md:hidden">
             <div className="scale-90 origin-right">
                <CrowdMeter />
             </div>
             <button 
                onClick={() => setIsMenuOpen(!isMenuOpen)}
                className="w-10 h-10 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-white z-50 relative active:scale-95 transition-transform"
             >
                {isMenuOpen ? <X size={20} /> : <Menu size={20} />}
             </button>
          </div>
        </div>
      </nav>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMenuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -20, scale: 0.95 }}
            transition={{ duration: 0.2 }}
            className="fixed inset-x-4 top-20 z-40 bg-slate-900/95 backdrop-blur-2xl border border-white/10 rounded-3xl p-6 md:hidden shadow-2xl overflow-hidden"
          >
             <div className="flex flex-col gap-4">
                {navLinks.map(link => (
                  <Link 
                    key={link.href} 
                    href={link.href}
                    onClick={() => setIsMenuOpen(false)}
                    className="text-lg font-bold text-slate-300 hover:text-white py-2 border-b border-white/5 last:border-0"
                  >
                    {link.label}
                  </Link>
                ))}
                
                <div className="h-px bg-white/10 my-2" />
                
                <Link 
                  href="/login"
                  onClick={() => setIsMenuOpen(false)} 
                  className="text-center py-3 text-slate-300 hover:text-white font-bold bg-slate-800 rounded-xl"
                >
                  Member Login
                </Link>
                <Link 
                  href="/pricing"
                  onClick={() => setIsMenuOpen(false)}
                  className="text-center py-3 bg-neon text-slate-950 font-black rounded-xl hover:bg-neon-hover shadow-lg shadow-neon/20"
                >
                  Join Now
                </Link>
             </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

'use client';

import React from 'react';
import QRCode from 'react-qr-code';
import { Fingerprint, ScanLine } from 'lucide-react';
import { useGymStore } from '@/lib/store';
import { currentUser } from '@/lib/mockData';
import { cn } from '@/lib/utils';
import { Activity } from 'lucide-react';

export default function DigitalPass() {
  const { accessMethod } = useGymStore();

  return (
    <div className="relative w-full max-w-sm mx-auto aspect-[3/4] rounded-3xl overflow-hidden bg-slate-900/50 backdrop-blur-xl border border-white/10 shadow-2xl group">
      {/* Background Gradients */}
      <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-emerald-500/10 via-transparent to-purple-500/10 opacity-50" />
      <div className="absolute -top-20 -right-20 w-40 h-40 bg-emerald-500/20 rounded-full blur-3xl animate-pulse" />
      
      {/* Card Content */}
      <div className="relative z-10 flex flex-col items-center justify-between h-full p-8 text-center">
        
        {/* Header */}
        <div className="w-full flex justify-between items-center opacity-80">
            <div className="flex items-center gap-2">
                <div className="w-6 h-6 rounded-full bg-emerald-500 text-slate-950 flex items-center justify-center">
                    <Activity size={14} strokeWidth={3} />
                </div>
                <span className="font-bold text-white tracking-tight">PulseFit</span>
            </div>
            <div className="text-[10px] font-mono text-emerald-400 border border-emerald-500/30 px-2 py-1 rounded">
                ACCESS PASS
            </div>
        </div>

        {/* Dynamic Entry Display */}
        <div className="flex-1 flex flex-col items-center justify-center w-full my-6">
           <div className="relative p-6 rounded-2xl bg-white/5 border border-white/10 shadow-inner">
               {accessMethod === 'qr' || accessMethod === 'both' ? (
                   <div className="bg-white p-4 rounded-xl relative">
                       <QRCode 
                           value={`user:${currentUser.id}`} 
                           size={180}
                           viewBox={`0 0 256 256`}
                           style={{ height: "auto", maxWidth: "100%", width: "100%" }}
                       />
