  // Leads
  leads: any[];
  setLeads: (leads: any[]) => void;

  // Staff
  staff: any[];
  setStaff: (staff: any[]) => void;
}

export interface SystemStatus {
  id: string;
  name: string;
  status: string;
  reportedAt: string;
}

export interface Plan {
    id: string;
    name: string;
    price: string;
    features: string[];
    activeMembers: number; 
}

// Initial Data Blocks (can be empty if strictly fetching, but good for first render)
const initialPlans: Plan[] = [
    { id: 'basic', name: 'Basic Plan', price: '3000', features: ['15-minute assessment', '98% accuracy rate', 'Sport-specific insights'], activeMembers: 142 },
    { id: 'business', name: 'Business Plan', price: '5000', features: ['15-minute assessment', '98% accuracy rate', 'Sport-specific insights', 'Priority Support'], activeMembers: 56 },
    { id: 'enterprise', name: 'Enterprise Plan', price: '8000', features: ['15-minute assessment', '98% accuracy rate', 'Sport-specific insights', 'Dedicated Agent'], activeMembers: 12 },
];

const initialSystems = [
    { id: 's1', name: 'Smart Lockers', status: 'Operational', reportedAt: '2026-01-29T10:30:00.000Z' }, 
    { id: 's2', name: 'Access Control', status: 'Operational', reportedAt: '2026-01-26T14:00:00.000Z' }, 
    { id: 's3', name: 'HVAC System', status: 'Maintenance', reportedAt: '2026-01-30T09:15:00.000Z' }, 
];

export const useGymStore = create<GymStore>()(
  persist(
    (set, get) => ({
      occupancy: 42,
      currentInside: 84,
      maxCapacity: 200,
      setOccupancy: (val) => set({ occupancy: val }),
      setCurrentInside: (val) => {
        const { maxCapacity } = get();
        set({ currentInside: val, occupancy: Math.min(100, Math.round((val / maxCapacity) * 100)) });
      },
      setMaxCapacity: (val) => {
        const { currentInside } = get();
        set({ maxCapacity: val, occupancy: Math.min(100, Math.round((currentInside / val) * 100)) });
      },
      accessMethod: 'qr',
      setAccessMethod: (method) => set({ accessMethod: method }),

      // Plans
      plans: initialPlans,
      setPlans: (plans) => set({ plans }),
      updatePlan: (updatedPlan) => set((state) => ({
          plans: state.plans.map(p => p.id === updatedPlan.id ? updatedPlan : p)
      })),

      // Maintenance
      systems: initialSystems,
      setSystems: (systems) => set({ systems }),
      updateSystem: (updatedSystem) => set((state) => ({
          systems: state.systems.map(s => s.id === updatedSystem.id ? updatedSystem : s)
      })),

      // New Modules
      members: [], 
      setMembers: (members) => set({ members }),
      
      leads: [],
      setLeads: (leads) => set({ leads }),

      staff: [],
      setStaff: (staff) => set({ staff }),
    }),
    {
      name: 'pulse-fit-gym-store', 
      storage: createJSONStorage(() => localStorage), 
      skipHydration: true, 
    }
  )
);

// SYNC ENGINE
if (typeof window !== 'undefined') {
  const channel = new BroadcastChannel('gym_sync_channel');
  
  // 1. Initial Fetch All
  import('@/lib/api').then(({ api }) => {
      const entities = ['Plans', 'Maintenance', 'Members', 'Leads', 'Staff'] as const;
      
      entities.forEach(type => {
          api.fetchData(type).then(data => {
              if (data && data.length > 0) {
                  // Only overwrite if remote has data
                  if (type === 'Plans') useGymStore.setState({ plans: data });
                  if (type === 'Maintenance') useGymStore.setState({ systems: data });
                  if (type === 'Members') useGymStore.setState({ members: data });
                  if (type === 'Leads') useGymStore.setState({ leads: data });
                  if (type === 'Staff') useGymStore.setState({ staff: data });
              }
          });
      });
  });

  // 2. Debounced Save Handlers
  const saveTimeouts: Record<string, NodeJS.Timeout> = {};

  // Implementing Closure for Dirty Checking
  let lastState = useGymStore.getState();
  
  useGymStore.subscribe((state) => {
      channel.postMessage(state);
      
      const checkAndSave = (key: keyof GymStore, type: any) => {
          if (state[key] !== lastState[key]) {
             // It changed
             clearTimeout(saveTimeouts[type]);
             saveTimeouts[type] = setTimeout(() => {
                 import('@/lib/api').then(({ api }) => {
                    // @ts-ignore
                    api.saveData(type, state[key]); 
                 });
             }, 2000); // 2s debounce
          }
      };

      checkAndSave('plans', 'Plans');
      checkAndSave('systems', 'Maintenance');
      checkAndSave('members', 'Members');
      checkAndSave('leads', 'Leads');
      checkAndSave('staff', 'Staff');

      lastState = state;
  });

  // Cross Tab Receive
  channel.onmessage = (event) => {
      useGymStore.setState(event.data);
  };
}
